import React, { createContext, useState, useContext, useEffect } from 'react';
import { validateCartAddition } from '../utils/radarService'; // Usamos tus validaciones existentes

const CartContext = createContext();

export const CartProvider = ({ children }) => {
  const [cart, setCart] = useState(() => {
    const savedCart = localStorage.getItem('active-cart');
    return savedCart ? JSON.parse(savedCart) : [];
  });

  // Guardar automáticamente en el storage cuando cambie el carrito
  useEffect(() => {
    localStorage.setItem('active-cart', JSON.stringify(cart));
  }, [cart]);

  const addToCart = (producto, modoEntrega = 'delivery') => {
    // 1. Usar tu lógica de validación profesional
    const validacion = validateCartAddition(cart, producto, modoEntrega);
    
    if (!validacion.valid) {
      return { success: false, msg: validacion.msg };
    }

    // 2. Si es válido, lo agregamos
    setCart(prev => [...prev, { ...producto, idCarrito: Date.now() }]);
    return { success: true, msg: "¡Producto agregado!" };
  };

  const removeFromCart = (idCarrito) => {
    setCart(prev => prev.filter(item => item.idCarrito !== idCarrito));
  };

  const clearCart = () => {
    setCart([]);
    localStorage.removeItem('active-cart');
  };

  const total = cart.reduce((acc, item) => acc + item.precioNuevo, 0);

  return (
    <CartContext.Provider value={{ 
      cart, 
      addToCart, 
      removeFromCart, 
      clearCart, 
      total,
      count: cart.length 
    }}>
      {children}
    </CartContext.Provider>
  );
};

export const useCart = () => useContext(CartContext);
